    public Bills(MainWin mainwin) {
        super(mainwin.getRoot(), "Rechnungen");

        initComponents();

        this.mainwin = mainwin;

        DBBill bill = new DBBill();

        tm = new TableManipulator(root, jTContent, bill);

        tm.hide(bill.hist.lo_user);
        tm.hide(bill.hist.lo_zeit);
        tm.hide(bill.hist.ae_user);
        tm.hide(bill.hist.an_user);
        tm.hide(bill.hist.an_zeit);
        tm.hide(bill.hist.ae_zeit);
        tm.hide(bill.bp_idx);
        tm.hide(bill.odt_data);
        tm.hide(bill.pdf_data);

        tm.prepareTable();

        feed_table(false);

        tm.autoResize();

        tableFilter1.setFilter(jTContent);
    }

    private void feed_table() {
        feed_table(true);
    }

    private void feed_table(boolean autombox) {
        new AutoMBox(getTitle(), autombox) {

            @Override
            public void do_stuff() throws Exception {

                tm.clear();

                Transaction trans = getTransaction();
                DBBill bill = new DBBill();
                values = trans.fetchTable2(bill, " where "
                        + trans.markColumn(bill, bill.bp_idx) + " = "
                        + mainwin.getBPIdx()
                        + " order by " + trans.markColumn(bill, bill.billingnr));

                for (DBBill entry : values) {
                    tm.add(entry);
                }
            }
        };
    }

